class Solution {
    public int[][] validArrangement(int[][] pairs) {
        Map<Integer, Deque<Integer>> graph = new HashMap<>();
        Map<Integer, Integer> inDegree = new HashMap<>();
        Map<Integer, Integer> outDegree = new HashMap<>();

        for (int[] pair : pairs) {
            int u = pair[0], v = pair[1];
            graph.computeIfAbsent(u, k -> new ArrayDeque<>()).add(v);
            outDegree.put(u, outDegree.getOrDefault(u, 0) + 1);
            inDegree.put(v, inDegree.getOrDefault(v, 0) + 1);
        }

        int start = pairs[0][0];
        for (int node : graph.keySet()) {
            if (outDegree.getOrDefault(node, 0) - inDegree.getOrDefault(node, 0) == 1) {
                start = node;
                break;
            }
        }

        List<int[]> res = new ArrayList<>();
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(start);
        while (!stack.isEmpty()) {
            int curr = stack.peek();
            if (graph.containsKey(curr) && !graph.get(curr).isEmpty()) {
                int next = graph.get(curr).poll();
                stack.push(next);
            } else {
                if (stack.size() > 1) {
                    int to = stack.pop();
                    int from = stack.peek();
                    res.add(new int[]{from, to});
                } else {
                    stack.pop();
                }
            }
        }
        Collections.reverse(res);
        return res.toArray(new int[0][]);
    }
}
